        const locale = localeMap[currentLang] || 'vi-VN';
        const time = lastSyncAt.toLocaleTimeString(locale, { hour:'2-digit', minute:'2-digit', second:'2-digit' });
        element.textContent = translate('last_sync', { time, count:allFlights.length });
